import React from 'react';
import './App.css';
import NavBar from './common/Navbar'
import Home from './Home'
import About from './About'
import NotFound from './not-found';
import { Switch, Route} from "react-router-dom";


function App() {
  return (
    <div>
      <NavBar />  
      <Switch>
        <Route path='/About'>
          <About />
        </Route>
        <Route exact path="/">
          <Home />
        </Route> 
        <Route path="*">
          <NotFound />
        </Route>
      </Switch> 
  </div>
  );
}

export default App;
