import React from 'react'
import './MastheadStyle.css'

const Masthead = () => {
    return (
        <div className="bd-masthead" style={{paddingBottom:"200px"}}>
            <div className="container">
                <div className="row">
                    <div className="col-6 mx-auto col-md-4 order-md-2">
                        <img src="https://vvce.acm.org/Assets/aicdmb.png" alt="aicdmb" width="512" height="430" className="img-fluid mb-3 mb-md-0"/>
                    </div>
                    <div className="col-md-8 order-md-1 text-center text-md-left pr-md-5">
                        <h1 className="mb-3 mastHead">Annual International Conference on Data Science, Machine Learning and Blockchain Technology (AICDMB)</h1>
                        <p className="mb-4 mt-3 mastPara">
                        <b>AICDMB</b> is an international conference dedicated to advances in Data Science, Machine Learning and Blockchain Technology. The conference is a yearly event for a world-class gathering of researchers from academia and industry, practitioners, and business leaders, providing a forum for discussing cutting edge research, and directions for new innovative business and technology.
                        </p>
                        <div className="d-flex flex-column flex-md-row mastBtn">
                            <a href="#topic" className="btn btn-lg btn-outline-dark mb-3">Get Started</a>
                        </div>
                    </div>
                </div>
            </div>
        </div>
     );
}
 
export default Masthead;