import React, { Component } from 'react'
import {Navbar, NavDropdown, Nav} from 'react-bootstrap'
import { NavLink , Link } from 'react-router-dom';

const NavBar = () => {
    return ( 
        <Navbar variant="light" expand="lg" style={{background: "linear-gradient(to right, rgb(127, 127, 213), rgb(134, 168, 231), rgb(145, 234, 228))"}}>
            <div className="container">
                <Navbar.Brand><Link to="/" exact className="navbar-brand"><img src="https://vvce.acm.org/Assets/aicdmb.png" height="50px" width="50px" alt=""/></Link></Navbar.Brand>
                <Navbar.Toggle aria-controls="basic-navbar-nav" />
                <Navbar.Collapse id="basic-navbar-nav">
                <Nav className="ml-auto">
                    <NavLink className="nav-item nav-link" to="/" exact>Home</NavLink>
                    <NavLink className="nav-item nav-link" to="/about" exact>About</NavLink>
                </Nav>
                </Navbar.Collapse>
            </div>   
        </Navbar>
     );
}
 
export default NavBar;