import React from 'react'
import '../cardStyles.css'

const Card = props => {
    const {topics} = props;

    return (
        <div className="flex-container" id="topic">
            { topics.map(topic => ( 
                <div key={topic._id} className="card flex-item my-1" style={{width: "18rem"}}>
                    <div className="card-body">
                        <h5 className="card-title">{topic.title}</h5>
                        <p className="card-text">{topic.desc}</p>
                    </div>
                </div>
            ))}
        </div>
     );
}
 
export default Card;